        const manifest = std.fmt.allocPrint(arena_alloc, "{{\"cluster_id\":\"zmq-cluster\",\"node_id\":{d},\"topics\":{d},\"streams\":{d},\"nodes\":{d},\"groups\":{d}}}", .{
            self.node_id,
            self.topics.count(),
            self.object_manager.streamCount(),
