        rh.serialize(buf, &wpos, resp_header_version);
        resp_body.serialize(buf, &wpos, api_version);
        return (self.allocator.realloc(buf, wpos) catch buf)[0..wpos];
    }

    fn validateDescribeClusterRequestFrame(buf: []const u8, start_pos: usize, api_version: i16) bool {
        var pos = start_pos;
        if (!skipFixedBytes(buf, &pos, 1)) return false; // include_cluster_authorized_operations
        if (api_version >= 1 and !skipFixedBytes(buf, &pos, 1)) return false; // endpoint_type
        ser.skipTaggedFields(buf, &pos) catch return false;
        return true;
    }

    // ---------------------------------------------------------------
    // DescribeProducers (key 61) — Return request-scoped producer state
    // ---------------------------------------------------------------
    fn handleDescribeProducers(self: *Broker, request_bytes: []const u8, body_start: usize, req_header: *const RequestHeader, api_version: i16, resp_header_version: i16) ?[]u8 {
        const Req = generated.describe_producers_request.DescribeProducersRequest;
        const Resp = generated.describe_producers_response.DescribeProducersResponse;
        const TopicResponse = Resp.TopicResponse;
        const PartitionResponse = TopicResponse.PartitionResponse;

        var pos = body_start;
        var req = Req.deserialize(self.allocator, request_bytes, &pos, api_version) catch |err| {
            log.warn("Failed to decode DescribeProducers request: {}", .{err});
            return null;
        };
        defer self.freeDescribeProducersRequest(&req);

        const topic_responses = self.allocator.alloc(TopicResponse, req.topics.len) catch return null;
        var topic_init: usize = 0;
        defer {
            self.freeDescribeProducersTopicResponses(topic_responses[0..topic_init]);
            if (topic_responses.len > 0) self.allocator.free(topic_responses);
        }

        for (req.topics) |topic_req| {
            const topic_name = topic_req.name orelse "";
            const topic_info = self.topics.get(topic_name);
            const partition_responses = self.allocator.alloc(PartitionResponse, topic_req.partition_indexes.len) catch return null;
            var partition_init: usize = 0;
            var transferred = false;
            defer {
                if (!transferred) {
                    self.freeDescribeProducersPartitions(partition_responses[0..partition_init]);
                    if (partition_responses.len > 0) self.allocator.free(partition_responses);
                }
            }

            for (topic_req.partition_indexes) |partition_index| {
                const partition_error: i16 = if (topic_info) |info|
                    if (partition_index >= 0 and partition_index < info.num_partitions)
                        @intFromEnum(ErrorCode.none)
                    else
                        @intFromEnum(ErrorCode.unknown_topic_or_partition)
                else
                    @intFromEnum(ErrorCode.unknown_topic_or_partition);

                const active_producers = if (partition_error == 0)
                    (self.collectDescribeProducerStates(topic_name, partition_index) catch return null)
                else
                    &[_]generated.describe_producers_response.DescribeProducersResponse.TopicResponse.PartitionResponse.ProducerState{};

                partition_responses[partition_init] = .{
                    .partition_index = partition_index,
                    .error_code = partition_error,
                    .error_message = null,
                    .active_producers = active_producers,
                };
                partition_init += 1;
            }

            topic_responses[topic_init] = .{
                .name = topic_req.name,
                .partitions = partition_responses,
            };
            topic_init += 1;
            transferred = true;
        }

        const resp_body = Resp{
            .throttle_time_ms = 0,
            .topics = topic_responses[0..topic_init],
        };
        const rh = ResponseHeader{ .correlation_id = req_header.correlation_id };
        const needed = rh.calcSize(resp_header_version) + resp_body.calcSize(api_version);
        var buf = self.allocator.alloc(u8, needed) catch return null;
        var wpos: usize = 0;
        rh.serialize(buf, &wpos, resp_header_version);
        resp_body.serialize(buf, &wpos, api_version);
        return (self.allocator.realloc(buf, wpos) catch buf)[0..wpos];
    }

    fn freeDescribeProducersRequest(self: *Broker, req: *generated.describe_producers_request.DescribeProducersRequest) void {
        for (req.topics) |topic| {
            if (topic.partition_indexes.len > 0) self.allocator.free(topic.partition_indexes);
        }
        if (req.topics.len > 0) self.allocator.free(req.topics);
    }

    fn freeDescribeProducersTopicResponses(self: *Broker, topics: []const generated.describe_producers_response.DescribeProducersResponse.TopicResponse) void {
        for (topics) |topic| {
            self.freeDescribeProducersPartitions(topic.partitions);
            if (topic.partitions.len > 0) self.allocator.free(topic.partitions);
        }
    }

    fn freeDescribeProducersPartitions(self: *Broker, partitions: []const generated.describe_producers_response.DescribeProducersResponse.TopicResponse.PartitionResponse) void {
        for (partitions) |partition| {
            if (partition.active_producers.len > 0) self.allocator.free(partition.active_producers);
        }
    }

    fn collectDescribeProducerStates(self: *Broker, topic: []const u8, partition_index: i32) ![]generated.describe_producers_response.DescribeProducersResponse.TopicResponse.PartitionResponse.ProducerState {
        const ProducerState = generated.describe_producers_response.DescribeProducersResponse.TopicResponse.PartitionResponse.ProducerState;

        var states = std.array_list.Managed(ProducerState).init(self.allocator);
        errdefer states.deinit();

        const partition_key = PartitionStore.hashPartitionKey(topic, partition_index);
        var seq_it = self.producer_sequences.iterator();
        while (seq_it.next()) |entry| {
            if (entry.key_ptr.partition_key != partition_key) continue;
            const state = entry.value_ptr.*;
            try states.append(.{
                .producer_id = entry.key_ptr.producer_id,
                .producer_epoch = @intCast(state.producer_epoch),
                .last_sequence = state.last_sequence,
                .last_timestamp = -1,
                .coordinator_epoch = 0,
                .current_txn_start_offset = -1,
            });
        }

        var txn_it = self.txn_coordinator.transactions.iterator();
        while (txn_it.next()) |entry| {
            const txn = entry.value_ptr;
            var matches_partition = false;
            for (txn.partitions.items) |tp| {
                if (tp.partition == partition_index and std.mem.eql(u8, tp.topic, topic)) {
                    matches_partition = true;
                    break;
                }
            }
            if (!matches_partition) continue;

            if (findDescribeProducerState(states.items, txn.producer_id)) |idx| {
                states.items[idx].producer_epoch = @intCast(txn.producer_epoch);
                states.items[idx].last_timestamp = txn.start_time_ms;
                states.items[idx].coordinator_epoch = if (txn.status == .ongoing) 0 else -1;
            } else {
                try states.append(.{
                    .producer_id = txn.producer_id,
                    .producer_epoch = @intCast(txn.producer_epoch),
                    .last_sequence = -1,
                    .last_timestamp = txn.start_time_ms,
                    .coordinator_epoch = if (txn.status == .ongoing) 0 else -1,
                    .current_txn_start_offset = -1,
                });
            }
        }

        if (states.items.len == 0) return &.{};
        return states.toOwnedSlice();
    }

    fn findDescribeProducerState(states: []const generated.describe_producers_response.DescribeProducersResponse.TopicResponse.PartitionResponse.ProducerState, producer_id: i64) ?usize {
        for (states, 0..) |state, idx| {
            if (state.producer_id == producer_id) return idx;
        }
        return null;
    }

    // ---------------------------------------------------------------
    // DescribeTopicPartitions (key 75) — paginated topic metadata
    // ---------------------------------------------------------------
    fn handleDescribeTopicPartitions(self: *Broker, request_bytes: []const u8, body_start: usize, req_header: *const RequestHeader, api_version: i16, resp_header_version: i16) ?[]u8 {
        const Req = generated.describe_topic_partitions_request.DescribeTopicPartitionsRequest;
        const Resp = generated.describe_topic_partitions_response.DescribeTopicPartitionsResponse;
        const TopicResponse = Resp.DescribeTopicPartitionsResponseTopic;

        if (!validateDescribeTopicPartitionsRequestFrame(request_bytes, body_start)) {
            log.warn("Malformed DescribeTopicPartitions request", .{});
            return null;
        }

        var pos = body_start;
        var req = Req.deserialize(self.allocator, request_bytes, &pos, api_version) catch |err| {
            log.warn("Failed to decode DescribeTopicPartitions request: {}", .{err});
            return null;
        };
        defer self.freeDescribeTopicPartitionsRequest(&req);

        var topic_responses: []TopicResponse = &.{};
        if (req.topics.len > 0) {
            topic_responses = self.allocator.alloc(TopicResponse, req.topics.len) catch return null;
        }
        var topic_init: usize = 0;
        defer {
            self.freeDescribeTopicPartitionsTopicResponses(topic_responses[0..topic_init]);
            if (topic_responses.len > 0) self.allocator.free(topic_responses);
        }

        const partition_limit: usize = if (req.response_partition_limit > 0)
            @intCast(req.response_partition_limit)
        else
            0;
        var emitted_partitions: usize = 0;
        var next_cursor: ?Resp.Cursor = null;

        var cursor_active = true;
        var cursor_topic: ?[]const u8 = null;
        var cursor_partition_index: i32 = 0;
        if (req.cursor) |cursor| {
            cursor_partition_index = @max(cursor.partition_index, 0);
            if (cursor.topic_name) |name| {
                cursor_topic = name;
                cursor_active = false;
            }
        }

        if (partition_limit > 0) {
            for (req.topics) |topic_req| {
                const topic_name = topic_req.name orelse "";
                var start_partition: i32 = 0;

                if (!cursor_active) {
                    if (!std.mem.eql(u8, topic_name, cursor_topic.?)) continue;
                    cursor_active = true;
                    start_partition = cursor_partition_index;
                }

                if (emitted_partitions >= partition_limit) {
                    next_cursor = .{ .topic_name = topic_req.name, .partition_index = 0 };
                    break;
                }

                const remaining_limit = partition_limit - emitted_partitions;
                const build = self.buildDescribeTopicPartitionsTopicResponse(topic_name, topic_req.name, start_partition, remaining_limit) catch return null;
                topic_responses[topic_init] = build.topic;
                topic_init += 1;
                emitted_partitions += build.emitted_partitions;

                if (build.next_partition_index) |partition_index| {
                    next_cursor = .{ .topic_name = topic_responses[topic_init - 1].name, .partition_index = partition_index };
                    break;
                }
            }
        }

        const resp = Resp{
            .throttle_time_ms = 0,
            .topics = topic_responses[0..topic_init],
            .next_cursor = next_cursor,
        };
        return self.serializeGeneratedResponse(req_header, resp_header_version, &resp, api_version);
    }

    const DescribeTopicPartitionsBuildResult = struct {
        topic: generated.describe_topic_partitions_response.DescribeTopicPartitionsResponse.DescribeTopicPartitionsResponseTopic,
        emitted_partitions: usize,
        next_partition_index: ?i32 = null,
    };

    fn freeDescribeTopicPartitionsRequest(self: *Broker, req: *generated.describe_topic_partitions_request.DescribeTopicPartitionsRequest) void {
        if (req.topics.len > 0) self.allocator.free(req.topics);
    }

    fn freeDescribeTopicPartitionsTopicResponses(self: *Broker, topics: []const generated.describe_topic_partitions_response.DescribeTopicPartitionsResponse.DescribeTopicPartitionsResponseTopic) void {
        for (topics) |topic| {
            self.freeDescribeTopicPartitionsPartitionResponses(topic.partitions);
            if (topic.partitions.len > 0) self.allocator.free(topic.partitions);
        }
    }

    fn freeDescribeTopicPartitionsPartitionResponses(self: *Broker, partitions: []const generated.describe_topic_partitions_response.DescribeTopicPartitionsResponse.DescribeTopicPartitionsResponseTopic.DescribeTopicPartitionsResponsePartition) void {
        for (partitions) |partition| {
            if (partition.replica_nodes.len > 0) self.allocator.free(partition.replica_nodes);
            if (partition.isr_nodes.len > 0) self.allocator.free(partition.isr_nodes);
            if (partition.eligible_leader_replicas.len > 0) self.allocator.free(partition.eligible_leader_replicas);
            if (partition.last_known_elr.len > 0) self.allocator.free(partition.last_known_elr);
            if (partition.offline_replicas.len > 0) self.allocator.free(partition.offline_replicas);
        }
    }

    fn buildDescribeTopicPartitionsTopicResponse(self: *Broker, topic_name: []const u8, response_name: ?[]const u8, start_partition_index: i32, max_partitions: usize) !DescribeTopicPartitionsBuildResult {
        const Resp = generated.describe_topic_partitions_response.DescribeTopicPartitionsResponse;
        const TopicResponse = Resp.DescribeTopicPartitionsResponseTopic;
        const PartitionResponse = TopicResponse.DescribeTopicPartitionsResponsePartition;

        if (topic_name.len == 0) {
            return .{ .topic = .{
                .error_code = @intFromEnum(ErrorCode.invalid_topic_exception),
                .name = response_name,
                .topic_id = zeroUuid(),
                .is_internal = false,
                .partitions = &.{},
                .topic_authorized_operations = std.math.minInt(i32),
            }, .emitted_partitions = 0 };
        }

        const topic_info = self.topics.getPtr(topic_name) orelse return .{ .topic = .{
            .error_code = @intFromEnum(ErrorCode.unknown_topic_or_partition),
            .name = response_name,
            .topic_id = zeroUuid(),
            .is_internal = false,
            .partitions = &.{},
            .topic_authorized_operations = std.math.minInt(i32),
        }, .emitted_partitions = 0 };

        const partition_total_i32: i32 = @max(topic_info.num_partitions, 0);
        if (start_partition_index >= partition_total_i32 or max_partitions == 0) {
            return .{ .topic = .{
                .error_code = @intFromEnum(ErrorCode.none),
                .name = topic_info.name,
                .topic_id = topic_info.topic_id,
                .is_internal = std.mem.startsWith(u8, topic_info.name, "__"),
                .partitions = &.{},
                .topic_authorized_operations = std.math.minInt(i32),
            }, .emitted_partitions = 0 };
        }

        const start_partition: usize = @intCast(@max(start_partition_index, 0));
        const available_partitions: usize = @intCast(partition_total_i32 - @as(i32, @intCast(start_partition)));
        const partition_count = @min(available_partitions, max_partitions);
        var partitions: []PartitionResponse = &.{};
        if (partition_count > 0) {
            partitions = try self.allocator.alloc(PartitionResponse, partition_count);
        }
        var partitions_init: usize = 0;
        errdefer {
            self.freeDescribeTopicPartitionsPartitionResponses(partitions[0..partitions_init]);
            if (partitions.len > 0) self.allocator.free(partitions);
        }

        for (0..partition_count) |offset| {
            const partition_index: i32 = @intCast(start_partition + offset);
            partitions[partitions_init] = try self.buildDescribeTopicPartitionsPartitionResponse(partition_index);
            partitions_init += 1;
        }

        const next_partition: ?i32 = if (start_partition + partition_count < @as(usize, @intCast(partition_total_i32)))
            @intCast(start_partition + partition_count)
        else
            null;

        return .{
            .topic = .{
                .error_code = @intFromEnum(ErrorCode.none),
                .name = topic_info.name,
                .topic_id = topic_info.topic_id,
                .is_internal = std.mem.startsWith(u8, topic_info.name, "__"),
                .partitions = partitions[0..partitions_init],
                .topic_authorized_operations = std.math.minInt(i32),
            },
            .emitted_partitions = partitions_init,
            .next_partition_index = next_partition,
        };
    }

    fn buildDescribeTopicPartitionsPartitionResponse(self: *Broker, partition_index: i32) !generated.describe_topic_partitions_response.DescribeTopicPartitionsResponse.DescribeTopicPartitionsResponseTopic.DescribeTopicPartitionsResponsePartition {
        const replicas = try self.allocator.alloc(i32, 1);
        errdefer self.allocator.free(replicas);
        replicas[0] = self.node_id;

        const isr = try self.allocator.alloc(i32, 1);
        errdefer self.allocator.free(isr);
        isr[0] = self.node_id;

        return .{
            .error_code = @intFromEnum(ErrorCode.none),
            .partition_index = partition_index,
            .leader_id = self.node_id,
            .leader_epoch = if (self.raft_state) |rs| rs.current_epoch else self.cached_leader_epoch,
            .replica_nodes = replicas,
            .isr_nodes = isr,
            .eligible_leader_replicas = &.{},
            .last_known_elr = &.{},
            .offline_replicas = &.{},
        };
    }

    // ---------------------------------------------------------------
    // AlterPartitionReassignments (key 45) — flexible versions only
    // ---------------------------------------------------------------
    fn handleAlterPartitionReassignments(self: *Broker, request_bytes: []const u8, body_start: usize, req_header: *const RequestHeader, api_version: i16, resp_header_version: i16) ?[]u8 {
        const Req = generated.alter_partition_reassignments_request.AlterPartitionReassignmentsRequest;
        const Resp = generated.alter_partition_reassignments_response.AlterPartitionReassignmentsResponse;
        const TopicResponse = Resp.ReassignableTopicResponse;
        const PartitionResponse = TopicResponse.ReassignablePartitionResponse;

        var pos = body_start;
        if (!validateAlterPartitionReassignmentsRequestFrame(request_bytes, body_start)) {
            log.warn("Malformed AlterPartitionReassignments request", .{});
            return null;
        }
        var req = Req.deserialize(self.allocator, request_bytes, &pos, api_version) catch |err| {
            log.warn("Failed to decode AlterPartitionReassignments request: {}", .{err});
            return null;
        };
        defer self.freeAlterPartitionReassignmentsRequest(&req);

        const responses = self.allocator.alloc(TopicResponse, req.topics.len) catch return null;
        var response_init: usize = 0;
        defer {
            self.freeAlterPartitionReassignmentsResponses(responses[0..response_init]);
            if (responses.len > 0) self.allocator.free(responses);
        }

        for (req.topics) |topic_req| {
            const topic_name = topic_req.name orelse "";
            const topic_info = self.topics.get(topic_name);
            const partitions = self.allocator.alloc(PartitionResponse, topic_req.partitions.len) catch return null;
            var transferred = false;
            defer {
                if (!transferred and partitions.len > 0) self.allocator.free(partitions);
            }

            for (topic_req.partitions, 0..) |partition_req, i| {
                partitions[i] = .{
                    .partition_index = partition_req.partition_index,
                    .error_code = self.applyPartitionReassignment(topic_name, topic_info, partition_req) catch @intFromEnum(ErrorCode.kafka_storage_error),
                    .error_message = null,
                };
            }

            responses[response_init] = .{
                .name = topic_req.name,
                .partitions = partitions,
            };
            response_init += 1;
            transferred = true;
        }

        const resp_body = Resp{
            .throttle_time_ms = 0,
            .error_code = @intFromEnum(ErrorCode.none),
            .error_message = null,
            .responses = responses[0..response_init],
        };
        const rh = ResponseHeader{ .correlation_id = req_header.correlation_id };
        const needed = rh.calcSize(resp_header_version) + resp_body.calcSize(api_version);
        var buf = self.allocator.alloc(u8, needed) catch return null;
        var wpos: usize = 0;
        rh.serialize(buf, &wpos, resp_header_version);
        resp_body.serialize(buf, &wpos, api_version);
        return (self.allocator.realloc(buf, wpos) catch buf)[0..wpos];
    }

    fn freeAlterPartitionReassignmentsRequest(self: *Broker, req: *generated.alter_partition_reassignments_request.AlterPartitionReassignmentsRequest) void {
        for (req.topics) |topic| {
            for (topic.partitions) |partition| {
                if (partition.replicas.len > 0) self.allocator.free(partition.replicas);
            }
            if (topic.partitions.len > 0) self.allocator.free(topic.partitions);
        }
        if (req.topics.len > 0) self.allocator.free(req.topics);
    }

    fn freeAlterPartitionReassignmentsResponses(self: *Broker, responses: []const generated.alter_partition_reassignments_response.AlterPartitionReassignmentsResponse.ReassignableTopicResponse) void {
        for (responses) |response| {
            if (response.partitions.len > 0) self.allocator.free(response.partitions);
        }
    }

    fn applyPartitionReassignment(self: *Broker, topic_name: []const u8, topic_info: ?TopicInfo, partition_req: generated.alter_partition_reassignments_request.AlterPartitionReassignmentsRequest.ReassignableTopic.ReassignablePartition) !i16 {
        const info = topic_info orelse return @intFromEnum(ErrorCode.unknown_topic_or_partition);
        if (partition_req.partition_index < 0 or partition_req.partition_index >= info.num_partitions) {
            return @intFromEnum(ErrorCode.unknown_topic_or_partition);
        }

        var key_buf: [256]u8 = undefined;
        const lookup_key = reassignmentKeyBuf(&key_buf, topic_name, partition_req.partition_index);

        if (partition_req.replicas.len == 0) {
            const removed_existing = self.partition_reassignments.fetchRemove(lookup_key);
            if (removed_existing) |removed| {
                self.persistPartitionReassignmentsDurably() catch |err| {
                    self.restorePartitionReassignmentMapEntry(removed);
                    return err;
                };
                self.freePartitionReassignmentMapEntry(removed);
                return @intFromEnum(ErrorCode.none);
            }
            return @intFromEnum(ErrorCode.no_reassignment_in_progress);
        }

        if (!validReplicaAssignment(partition_req.replicas)) {
            return @intFromEnum(ErrorCode.invalid_replica_assignment);
        }

        if (isLocalReplicaAssignment(partition_req.replicas, self.node_id)) {
            const removed_existing = self.partition_reassignments.fetchRemove(lookup_key);
            if (removed_existing) |removed| {
                self.persistPartitionReassignmentsDurably() catch |err| {
                    self.restorePartitionReassignmentMapEntry(removed);
                    return err;
                };
                self.freePartitionReassignmentMapEntry(removed);
            }
            return @intFromEnum(ErrorCode.none);
        }

        const owned_key = try reassignmentKey(self.allocator, topic_name, partition_req.partition_index);
        var owned_key_owned = true;
        errdefer if (owned_key_owned) self.allocator.free(owned_key);
        var next = try self.buildPartitionReassignment(topic_name, partition_req.partition_index, partition_req.replicas);
        var next_owned = true;
        errdefer if (next_owned) next.deinit(self.allocator);

        const removed_existing = self.partition_reassignments.fetchRemove(lookup_key);

        self.partition_reassignments.put(owned_key, next) catch |err| {
            if (removed_existing) |removed| {
                self.restorePartitionReassignmentMapEntry(removed);
            }
            return err;
        };
        owned_key_owned = false;
        next_owned = false;

        self.persistPartitionReassignmentsDurably() catch |err| {
            if (self.partition_reassignments.fetchRemove(lookup_key)) |inserted| {
                self.freePartitionReassignmentMapEntry(inserted);
            }
            if (removed_existing) |removed| {
                self.restorePartitionReassignmentMapEntry(removed);
            }
            return err;
        };

        if (removed_existing) |removed| {
            self.freePartitionReassignmentMapEntry(removed);
        }

        return @intFromEnum(ErrorCode.none);
    }

