        var wpos: usize = 0;
        rh.serialize(buf, &wpos, resp_header_version);
        resp_body.serialize(buf, &wpos, api_version);
        return (self.allocator.realloc(buf, wpos) catch buf)[0..wpos];
    }

    fn freeListPartitionReassignmentsRequest(self: *Broker, req: *generated.list_partition_reassignments_request.ListPartitionReassignmentsRequest) void {
        if (req.topics) |topics| {
            for (topics) |topic| {
                if (topic.partition_indexes.len > 0) self.allocator.free(topic.partition_indexes);
            }
            if (topics.len > 0) self.allocator.free(topics);
        }
    }

    fn buildListPartitionReassignmentsTopics(self: *Broker, req: *const generated.list_partition_reassignments_request.ListPartitionReassignmentsRequest) ![]generated.list_partition_reassignments_response.ListPartitionReassignmentsResponse.OngoingTopicReassignment {
        const TopicResponse = generated.list_partition_reassignments_response.ListPartitionReassignmentsResponse.OngoingTopicReassignment;

        var topics = std.array_list.Managed(TopicResponse).init(self.allocator);
        errdefer {
            self.freeListPartitionReassignmentsTopics(topics.items);
            topics.deinit();
        }

        if (req.topics == null) {
            var seen = std.array_list.Managed([]const u8).init(self.allocator);
            defer seen.deinit();

            var it = self.partition_reassignments.iterator();
            while (it.next()) |entry| {
                if (containsTopicName(seen.items, entry.value_ptr.topic)) continue;
                try seen.append(entry.value_ptr.topic);
                try self.appendListPartitionReassignmentTopic(&topics, entry.value_ptr.topic, &.{});
            }
        } else {
            for (req.topics.?) |topic_req| {
                const topic_name = topic_req.name orelse "";
                try self.appendListPartitionReassignmentTopic(&topics, topic_name, topic_req.partition_indexes);
            }
        }

        if (topics.items.len == 0) return &.{};
        return try topics.toOwnedSlice();
    }

    fn appendListPartitionReassignmentTopic(
        self: *Broker,
        topics: *std.array_list.Managed(generated.list_partition_reassignments_response.ListPartitionReassignmentsResponse.OngoingTopicReassignment),
        topic_name: []const u8,
        partition_indexes: []const i32,
    ) !void {
        const TopicResponse = generated.list_partition_reassignments_response.ListPartitionReassignmentsResponse.OngoingTopicReassignment;
        const PartitionResponse = TopicResponse.OngoingPartitionReassignment;

        var partitions = std.array_list.Managed(PartitionResponse).init(self.allocator);
        errdefer {
            self.freeListPartitionReassignmentPartitions(partitions.items);
            partitions.deinit();
        }

        if (partition_indexes.len > 0) {
            for (partition_indexes) |partition_index| {
                var key_buf: [256]u8 = undefined;
                const lookup_key = reassignmentKeyBuf(&key_buf, topic_name, partition_index);
                if (self.partition_reassignments.get(lookup_key)) |state| {
                    try partitions.append(try self.listPartitionReassignmentFromState(state));
                }
            }
        } else {
            var it = self.partition_reassignments.iterator();
            while (it.next()) |entry| {
                if (!std.mem.eql(u8, entry.value_ptr.topic, topic_name)) continue;
                try partitions.append(try self.listPartitionReassignmentFromState(entry.value_ptr.*));
            }
        }

        if (partitions.items.len == 0) return;
        const owned_partitions = try partitions.toOwnedSlice();
        errdefer {
            self.freeListPartitionReassignmentPartitions(owned_partitions);
            self.allocator.free(owned_partitions);
        }
        try topics.append(.{
            .name = topic_name,
            .partitions = owned_partitions,
        });
    }

    fn listPartitionReassignmentFromState(self: *Broker, state: PartitionReassignment) !generated.list_partition_reassignments_response.ListPartitionReassignmentsResponse.OngoingTopicReassignment.OngoingPartitionReassignment {
        const replicas = try self.allocator.dupe(i32, state.replicas);
        errdefer if (replicas.len > 0) self.allocator.free(replicas);
        const adding = try self.allocator.dupe(i32, state.adding_replicas);
        errdefer if (adding.len > 0) self.allocator.free(adding);
        const removing = try self.allocator.dupe(i32, state.removing_replicas);
        errdefer if (removing.len > 0) self.allocator.free(removing);

        return .{
            .partition_index = state.partition_index,
            .replicas = replicas,
            .adding_replicas = adding,
            .removing_replicas = removing,
        };
    }

    fn freeListPartitionReassignmentsTopics(self: *Broker, topics: []const generated.list_partition_reassignments_response.ListPartitionReassignmentsResponse.OngoingTopicReassignment) void {
        for (topics) |topic| {
            self.freeListPartitionReassignmentPartitions(topic.partitions);
            if (topic.partitions.len > 0) self.allocator.free(topic.partitions);
        }
    }

    fn freeListPartitionReassignmentPartitions(self: *Broker, partitions: []const generated.list_partition_reassignments_response.ListPartitionReassignmentsResponse.OngoingTopicReassignment.OngoingPartitionReassignment) void {
        for (partitions) |partition| {
            if (partition.replicas.len > 0) self.allocator.free(partition.replicas);
            if (partition.adding_replicas.len > 0) self.allocator.free(partition.adding_replicas);
            if (partition.removing_replicas.len > 0) self.allocator.free(partition.removing_replicas);
        }
    }

    fn buildPartitionReassignment(self: *Broker, topic_name: []const u8, partition_index: i32, replicas: []const i32) !PartitionReassignment {
        const topic_copy = try self.allocator.dupe(u8, topic_name);
        errdefer self.allocator.free(topic_copy);
        const replicas_copy = try self.allocator.dupe(i32, replicas);
        errdefer self.allocator.free(replicas_copy);
        const adding = try filterAddingReplicas(self.allocator, replicas, self.node_id);
        errdefer if (adding.len > 0) self.allocator.free(adding);
        const removing = try filterRemovingReplicas(self.allocator, replicas, self.node_id);
        errdefer if (removing.len > 0) self.allocator.free(removing);

        return .{
            .topic = topic_copy,
            .partition_index = partition_index,
            .replicas = replicas_copy,
            .adding_replicas = adding,
            .removing_replicas = removing,
        };
    }

    fn partitionReassignmentFromEntry(self: *Broker, entry: MetadataPersistence.PartitionReassignmentEntry) !PartitionReassignment {
        const topic_copy = try self.allocator.dupe(u8, entry.topic);
        errdefer self.allocator.free(topic_copy);
        const replicas_copy = try self.allocator.dupe(i32, entry.replicas);
        errdefer if (replicas_copy.len > 0) self.allocator.free(replicas_copy);
        const adding_copy = try self.allocator.dupe(i32, entry.adding_replicas);
        errdefer if (adding_copy.len > 0) self.allocator.free(adding_copy);
        const removing_copy = try self.allocator.dupe(i32, entry.removing_replicas);
        errdefer if (removing_copy.len > 0) self.allocator.free(removing_copy);

        return .{
            .topic = topic_copy,
            .partition_index = entry.partition_index,
            .replicas = replicas_copy,
            .adding_replicas = adding_copy,
            .removing_replicas = removing_copy,
        };
    }

    fn clearPartitionReassignments(self: *Broker) void {
        var it = self.partition_reassignments.iterator();
        while (it.next()) |entry| {
            self.allocator.free(entry.key_ptr.*);
            entry.value_ptr.deinit(self.allocator);
        }
        self.partition_reassignments.clearRetainingCapacity();
    }

    fn freePartitionReassignmentMapEntry(self: *Broker, removed: anytype) void {
        self.allocator.free(removed.key);
        var value = removed.value;
        value.deinit(self.allocator);
    }

    fn restorePartitionReassignmentMapEntry(self: *Broker, removed: anytype) void {
        self.partition_reassignments.put(removed.key, removed.value) catch |restore_err| {
            log.err("Failed to restore partition reassignment after snapshot write failure: {}", .{restore_err});
            self.freePartitionReassignmentMapEntry(removed);
        };
    }

    fn pruneInvalidPartitionReassignments(self: *Broker) bool {
        var removed_any = false;
        while (true) {
            var key_to_remove: ?[]const u8 = null;
            var it = self.partition_reassignments.iterator();
            while (it.next()) |entry| {
                const info = self.topics.get(entry.value_ptr.topic);
                if (info == null or entry.value_ptr.partition_index < 0 or
                    entry.value_ptr.partition_index >= info.?.num_partitions or
                    entry.value_ptr.replicas.len == 0 or
                    !validReplicaAssignment(entry.value_ptr.replicas) or
                    isLocalReplicaAssignment(entry.value_ptr.replicas, self.node_id))
                {
                    key_to_remove = entry.key_ptr.*;
                    break;
                }
            }

            const key = key_to_remove orelse break;
            if (self.partition_reassignments.fetchRemove(key)) |removed| {
                self.freePartitionReassignmentMapEntry(removed);
                removed_any = true;
            } else {
                break;
            }
        }
        return removed_any;
    }

    fn reassignmentKey(allocator: Allocator, topic_name: []const u8, partition_index: i32) ![]u8 {
        return try std.fmt.allocPrint(allocator, "{s}-{d}", .{ topic_name, partition_index });
    }

    fn reassignmentKeyBuf(buf: []u8, topic_name: []const u8, partition_index: i32) []const u8 {
        return std.fmt.bufPrint(buf, "{s}-{d}", .{ topic_name, partition_index }) catch topic_name;
    }

    fn validReplicaAssignment(replicas: []const i32) bool {
        for (replicas, 0..) |replica, i| {
            if (replica < 0) return false;
            for (replicas[0..i]) |previous| {
                if (previous == replica) return false;
            }
        }
        return true;
    }

    fn isLocalReplicaAssignment(replicas: []const i32, node_id: i32) bool {
        return replicas.len == 1 and replicas[0] == node_id;
    }

    fn filterAddingReplicas(allocator: Allocator, replicas: []const i32, node_id: i32) ![]i32 {
        var list = std.array_list.Managed(i32).init(allocator);
        defer list.deinit();
        for (replicas) |replica| {
            if (replica != node_id) try list.append(replica);
        }
        if (list.items.len == 0) return &.{};
        return try list.toOwnedSlice();
    }

    fn filterRemovingReplicas(allocator: Allocator, replicas: []const i32, node_id: i32) ![]i32 {
        if (containsReplica(replicas, node_id)) return &.{};
        const removing = try allocator.alloc(i32, 1);
        removing[0] = node_id;
        return removing;
    }

    fn containsReplica(replicas: []const i32, node_id: i32) bool {
        for (replicas) |replica| {
            if (replica == node_id) return true;
        }
        return false;
    }

    fn containsTopicName(topics: []const []const u8, topic_name: []const u8) bool {
        for (topics) |topic| {
            if (std.mem.eql(u8, topic, topic_name)) return true;
        }
        return false;
    }

    fn validateAlterPartitionReassignmentsRequestFrame(buf: []const u8, start_pos: usize) bool {
        var pos = start_pos;
        if (!skipFixedBytes(buf, &pos, 4)) return false; // timeout_ms
        const topic_count = (ser.readCompactArrayLen(buf, &pos) catch return false) orelse 0;
        for (0..topic_count) |_| {
            _ = ser.readCompactString(buf, &pos) catch return false;
            const partition_count = (ser.readCompactArrayLen(buf, &pos) catch return false) orelse 0;
            for (0..partition_count) |_| {
                if (!skipFixedBytes(buf, &pos, 4)) return false; // partition_index
                if (!skipCompactI32Array(buf, &pos)) return false; // replicas
                ser.skipTaggedFields(buf, &pos) catch return false;
            }
            ser.skipTaggedFields(buf, &pos) catch return false;
        }
        ser.skipTaggedFields(buf, &pos) catch return false;
        return true;
    }

    fn validateListPartitionReassignmentsRequestFrame(buf: []const u8, start_pos: usize) bool {
        var pos = start_pos;
        if (!skipFixedBytes(buf, &pos, 4)) return false; // timeout_ms
        const topic_count = (ser.readCompactArrayLen(buf, &pos) catch return false) orelse 0;
        for (0..topic_count) |_| {
            _ = ser.readCompactString(buf, &pos) catch return false;
            if (!skipCompactI32Array(buf, &pos)) return false; // partition_indexes
            ser.skipTaggedFields(buf, &pos) catch return false;
        }
        ser.skipTaggedFields(buf, &pos) catch return false;
        return true;
    }

    fn validateBeginQuorumEpochRequestFrame(buf: []const u8, start_pos: usize, api_version: i16) bool {
        const flexible = api_version >= 1;
        var pos = start_pos;

        if (!skipKafkaString(buf, &pos, flexible)) return false; // cluster_id
        if (flexible and !skipFixedBytes(buf, &pos, 4)) return false; // voter_id
        if (!skipBeginQuorumTopics(buf, &pos, flexible)) return false;
        if (flexible and !skipQuorumLeaderEndpoints(buf, &pos)) return false;
        if (flexible) ser.skipTaggedFields(buf, &pos) catch return false;
        return true;
    }

    fn validateEndQuorumEpochRequestFrame(buf: []const u8, start_pos: usize, api_version: i16) bool {
        const flexible = api_version >= 1;
        var pos = start_pos;

        if (!skipKafkaString(buf, &pos, flexible)) return false; // cluster_id
        if (!skipEndQuorumTopics(buf, &pos, flexible)) return false;
        if (flexible and !skipQuorumLeaderEndpoints(buf, &pos)) return false;
        if (flexible) ser.skipTaggedFields(buf, &pos) catch return false;
        return true;
    }

    fn validateOffsetDeleteRequestFrame(buf: []const u8, start_pos: usize) bool {
        var pos = start_pos;

        if (!skipKafkaString(buf, &pos, false)) return false; // group_id
        const topic_count = readKafkaArrayCount(buf, &pos, false) orelse return false;
        for (0..topic_count) |_| {
            if (!skipKafkaString(buf, &pos, false)) return false; // topic name
            const partition_count = readKafkaArrayCount(buf, &pos, false) orelse return false;
            if (partition_count > (buf.len - pos) / 4) return false;
            pos += partition_count * 4;
        }
        return true;
    }

    fn validateDescribeClientQuotasRequestFrame(buf: []const u8, start_pos: usize, api_version: i16) bool {
        const flexible = api_version >= 1;
        var pos = start_pos;

        const components = readKafkaArrayHeader(buf, &pos, flexible) orelse return false;
        if (components.is_null) return false;
        for (0..components.count) |_| {
            if (!skipKafkaString(buf, &pos, flexible)) return false; // entity_type
            if (!skipFixedBytes(buf, &pos, 1)) return false; // match_type
            if (!skipKafkaString(buf, &pos, flexible)) return false; // match
            if (flexible) ser.skipTaggedFields(buf, &pos) catch return false;
        }

        if (!skipFixedBytes(buf, &pos, 1)) return false; // strict
        if (flexible) ser.skipTaggedFields(buf, &pos) catch return false;
        return true;
    }

    fn validateAlterClientQuotasRequestFrame(buf: []const u8, start_pos: usize, api_version: i16) bool {
        const flexible = api_version >= 1;
        var pos = start_pos;

        const entries = readKafkaArrayHeader(buf, &pos, flexible) orelse return false;
        if (entries.is_null) return false;
        for (0..entries.count) |_| {
            const entities = readKafkaArrayHeader(buf, &pos, flexible) orelse return false;
            if (entities.is_null) return false;
            for (0..entities.count) |_| {
                if (!skipKafkaString(buf, &pos, flexible)) return false; // entity_type
                if (!skipKafkaString(buf, &pos, flexible)) return false; // entity_name
                if (flexible) ser.skipTaggedFields(buf, &pos) catch return false;
            }

            const ops = readKafkaArrayHeader(buf, &pos, flexible) orelse return false;
            if (ops.is_null) return false;
            for (0..ops.count) |_| {
                if (!skipKafkaString(buf, &pos, flexible)) return false; // key
                if (!skipFixedBytes(buf, &pos, 9)) return false; // value + remove
                if (flexible) ser.skipTaggedFields(buf, &pos) catch return false;
            }
            if (flexible) ser.skipTaggedFields(buf, &pos) catch return false;
        }

        if (!skipFixedBytes(buf, &pos, 1)) return false; // validate_only
        if (flexible) ser.skipTaggedFields(buf, &pos) catch return false;
        return true;
    }

    fn validateDescribeUserScramCredentialsRequestFrame(buf: []const u8, start_pos: usize) bool {
        var pos = start_pos;

        const users = readKafkaArrayHeader(buf, &pos, true) orelse return false;
        if (!users.is_null) {
            for (0..users.count) |_| {
                if (!skipKafkaString(buf, &pos, true)) return false; // user name
                ser.skipTaggedFields(buf, &pos) catch return false;
            }
        }

        ser.skipTaggedFields(buf, &pos) catch return false;
        return true;
    }

    fn validateAlterUserScramCredentialsRequestFrame(buf: []const u8, start_pos: usize) bool {
        var pos = start_pos;

        const deletions = readKafkaArrayHeader(buf, &pos, true) orelse return false;
        if (deletions.is_null) return false;
        for (0..deletions.count) |_| {
            if (!skipKafkaString(buf, &pos, true)) return false; // name
            if (!skipFixedBytes(buf, &pos, 1)) return false; // mechanism
            ser.skipTaggedFields(buf, &pos) catch return false;
        }

        const upsertions = readKafkaArrayHeader(buf, &pos, true) orelse return false;
        if (upsertions.is_null) return false;
        for (0..upsertions.count) |_| {
            if (!skipKafkaString(buf, &pos, true)) return false; // name
            if (!skipFixedBytes(buf, &pos, 5)) return false; // mechanism + iterations
            if (!skipKafkaBytes(buf, &pos, true)) return false; // salt
            if (!skipKafkaBytes(buf, &pos, true)) return false; // salted_password
            ser.skipTaggedFields(buf, &pos) catch return false;
        }

        ser.skipTaggedFields(buf, &pos) catch return false;
        return true;
    }

    fn validateUpdateFeaturesRequestFrame(buf: []const u8, start_pos: usize, api_version: i16) bool {
        var pos = start_pos;

        if (!skipFixedBytes(buf, &pos, 4)) return false; // timeout_ms
        const updates = readKafkaArrayHeader(buf, &pos, true) orelse return false;
        if (updates.is_null) return false;
        for (0..updates.count) |_| {
            const feature = ser.readCompactString(buf, &pos) catch return false;
            if (feature == null) return false;
            if (!skipFixedBytes(buf, &pos, 2)) return false; // max_version_level
            if (api_version == 0) {
                if (!skipFixedBytes(buf, &pos, 1)) return false; // allow_downgrade
            } else {
                if (!skipFixedBytes(buf, &pos, 1)) return false; // upgrade_type
            }
            ser.skipTaggedFields(buf, &pos) catch return false;
        }

        if (api_version >= 1 and !skipFixedBytes(buf, &pos, 1)) return false; // validate_only
        ser.skipTaggedFields(buf, &pos) catch return false;
        return true;
    }

    fn validateGetTelemetrySubscriptionsRequestFrame(buf: []const u8, start_pos: usize) bool {
        var pos = start_pos;
        if (!skipFixedBytes(buf, &pos, 16)) return false; // client_instance_id
        ser.skipTaggedFields(buf, &pos) catch return false;
        return true;
    }

    fn validatePushTelemetryRequestFrame(buf: []const u8, start_pos: usize) bool {
        var pos = start_pos;
        if (!skipFixedBytes(buf, &pos, 16)) return false; // client_instance_id
        if (!skipFixedBytes(buf, &pos, 6)) return false; // subscription_id + terminating + compression_type
        const metrics = ser.readCompactBytes(buf, &pos) catch return false;
        if (metrics == null) return false;
        ser.skipTaggedFields(buf, &pos) catch return false;
        return true;
    }

    fn validateAssignReplicasToDirsRequestFrame(buf: []const u8, start_pos: usize) bool {
        var pos = start_pos;
        if (!skipFixedBytes(buf, &pos, 12)) return false; // broker_id + broker_epoch
        const directory_count = readKafkaArrayCount(buf, &pos, true) orelse return false;
        for (0..directory_count) |_| {
            if (!skipFixedBytes(buf, &pos, 16)) return false; // directory_id
            const topic_count = readKafkaArrayCount(buf, &pos, true) orelse return false;
            for (0..topic_count) |_| {
                if (!skipFixedBytes(buf, &pos, 16)) return false; // topic_id
                const partition_count = readKafkaArrayCount(buf, &pos, true) orelse return false;
                for (0..partition_count) |_| {
                    if (!skipFixedBytes(buf, &pos, 4)) return false; // partition_index
                    ser.skipTaggedFields(buf, &pos) catch return false;
                }
                ser.skipTaggedFields(buf, &pos) catch return false;
            }
            ser.skipTaggedFields(buf, &pos) catch return false;
        }
        ser.skipTaggedFields(buf, &pos) catch return false;
        return pos == buf.len;
    }

    fn validateListClientMetricsResourcesRequestFrame(buf: []const u8, start_pos: usize) bool {
        var pos = start_pos;
        ser.skipTaggedFields(buf, &pos) catch return false;
        return true;
    }

    fn validateOffsetForLeaderEpochRequestFrame(buf: []const u8, start_pos: usize, api_version: i16) bool {
        const flexible = api_version >= 4;
        var pos = start_pos;

        if (api_version >= 3 and !skipFixedBytes(buf, &pos, 4)) return false; // replica_id
        const topic_count = readKafkaArrayCount(buf, &pos, flexible) orelse return false;
        for (0..topic_count) |_| {
            if (!skipKafkaString(buf, &pos, flexible)) return false; // topic
            const partition_count = readKafkaArrayCount(buf, &pos, flexible) orelse return false;
            for (0..partition_count) |_| {
                if (!skipFixedBytes(buf, &pos, 4)) return false; // partition
                if (api_version >= 2 and !skipFixedBytes(buf, &pos, 4)) return false; // current_leader_epoch
                if (!skipFixedBytes(buf, &pos, 4)) return false; // leader_epoch
                if (flexible) ser.skipTaggedFields(buf, &pos) catch return false;
            }
            if (flexible) ser.skipTaggedFields(buf, &pos) catch return false;
        }
        if (flexible) ser.skipTaggedFields(buf, &pos) catch return false;
        return true;
    }

    fn validateWriteTxnMarkersRequestFrame(buf: []const u8, start_pos: usize, api_version: i16) bool {
        const flexible = api_version >= 1;
        var pos = start_pos;

        const marker_count = readKafkaArrayCount(buf, &pos, flexible) orelse return false;
        for (0..marker_count) |_| {
            if (!skipFixedBytes(buf, &pos, 11)) return false; // producer_id + producer_epoch + transaction_result
            const topic_count = readKafkaArrayCount(buf, &pos, flexible) orelse return false;
            for (0..topic_count) |_| {
                if (!skipKafkaString(buf, &pos, flexible)) return false; // topic name
                if (!skipKafkaI32Array(buf, &pos, flexible)) return false; // partition_indexes
                if (flexible) ser.skipTaggedFields(buf, &pos) catch return false;
            }
            if (!skipFixedBytes(buf, &pos, 4)) return false; // coordinator_epoch
            if (flexible) ser.skipTaggedFields(buf, &pos) catch return false;
        }
        if (flexible) ser.skipTaggedFields(buf, &pos) catch return false;
        return true;
    }

    fn validateTxnOffsetCommitRequestFrame(buf: []const u8, start_pos: usize, api_version: i16) bool {
        const flexible = api_version >= 3;
        var pos = start_pos;

        if (!skipKafkaString(buf, &pos, flexible)) return false; // transactional_id
        if (!skipKafkaString(buf, &pos, flexible)) return false; // group_id
        if (!skipFixedBytes(buf, &pos, 10)) return false; // producer_id + producer_epoch
        if (api_version >= 3) {
            if (!skipFixedBytes(buf, &pos, 4)) return false; // generation_id
            if (!skipKafkaString(buf, &pos, true)) return false; // member_id
            if (!skipKafkaString(buf, &pos, true)) return false; // group_instance_id
        }

        const topic_count = readKafkaArrayCount(buf, &pos, flexible) orelse return false;
        for (0..topic_count) |_| {
            if (!skipKafkaString(buf, &pos, flexible)) return false; // topic name
            const partition_count = readKafkaArrayCount(buf, &pos, flexible) orelse return false;
            for (0..partition_count) |_| {
                if (!skipFixedBytes(buf, &pos, 12)) return false; // partition_index + committed_offset
                if (api_version >= 2 and !skipFixedBytes(buf, &pos, 4)) return false; // committed_leader_epoch
                if (!skipKafkaString(buf, &pos, flexible)) return false; // committed_metadata
                if (flexible) ser.skipTaggedFields(buf, &pos) catch return false;
            }
