    const object_count_before = mock_s3.objectCount();
    mock_s3.failNextPutObjects(3);

    const partitions = [_]i32{0};
    const topics = [_]Topic{.{
        .name = "txn-add-parts-snapshot-fail-topic",
        .partitions = &partitions,
    }};
    const txns = [_]Txn{.{
