        .reason = "incompatible-protocol",
    };

    var bad_buf: [512]u8 = undefined;
    var bad_pos = buildTestRequest(&bad_buf, 11, 9, 1111, header_mod.requestHeaderVersion(11, 9));
    bad_req.serialize(&bad_buf, &bad_pos, 9);

