    try testing.expectEqual(@as(i32, -1), bad_resp.generation_id);
    try testing.expectEqual(@as(usize, 0), bad_resp.members.len);
    try testing.expectEqual(@as(usize, 1), group.memberCount());

    const bad_timeout_req = Req{
